    @Autowired
    private UserRepository userRepository;

    // Generate recovery codes for users when they enable two-factor authentication
    @Override
    public void generateRecoveryCodes(String username) {
        User user = userRepository.findByUsername(username).orElseThrow();
        List<String> recoveryCodes = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            String code = RandomStringUtils.randomNumeric(6);
            recoveryCodes.add(code);
            user.setBackupCode(code);
            userRepository.save(user);
        }
    }

    @Override
    public Authentication validateBackupCode(String username, String backupCode) {
        User user = userRepository.findByUsername(username).orElseThrow();
        if (user.getBackupCode().equals(backupCode)) {
            return new UsernamePasswordAuthenticationToken(user, null, Authorities.of("BACKUP_CODE_AUTH"));
        }
        return null;
    }

    @Override
    public boolean isTwoFactorEnabled(String username) {
        User user = userRepository.findByUsername(username).orElseThrow();
        return user.isMfaEnabled();
    }
